#include <unistd.h>
#include <string.h>

int main(void) {
    long ps = sysconf(_SC_PAGESIZE);
    size_t size = (size_t)ps * 4;
    char *m = (char *)mmap(NULL, size,
        PROT_READ | PROT_WRITE,
        MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
    if (m == MAP_FAILED) { perror("mmap"); return 1; }
    size_t npages = size / (size_t)ps;
    unsigned char vec[4];
    memset(m, 'A', (size_t)ps);
    memset(m + 2 * ps, 'C', (size_t)ps);
    int rc = ____(m, size, ____);
    printf("mincore result: %d\n", rc);
    int resident = 0;
    for (size_t i = 0; i < npages; i++) {
        printf("Page %zu: %s\n", i, (vec[i] & 1) ? "resident" : "not resident");
        if (vec[i] & 1) resident++;
    }
    printf("Resident pages: %d/%zu\n", resident, npages);
    printf("At least 2 resident: %s\n", resident >= 2 ? "yes" : "no");
    munmap(m, size);
    return 0;
}

