/* == EXEMPLE: mincore sur 1 page ====================== */
void example_mincore(void) {
    long ps = sysconf(_SC_PAGESIZE);
    char *p = mmap(NULL, (size_t)ps, PROT_READ|PROT_WRITE, MAP_PRIVATE|MAP_ANONYMOUS, -1, 0);
    p[0] = 'x';
    unsigned char v;
    mincore(p, (size_t)ps, &v);
    printf("1 page resident: %d\n", v & 1);
    munmap(p, (size_t)ps);
}

